def test_threshold_text_chromium_tuple():
    """Test that chromium_tuple returns the correct key-value pair."""
    qt_64_def = _DEFINITIONS[Variant.qt_64]

    for setting in qt_64_def._settings:
        if setting.option == 'threshold.text':
            key, value = setting.chromium_tuple(100)
            assert key == 'ForegroundBrightnessThreshold', (
                f"Expected key 'ForegroundBrightnessThreshold', got '{key}'"
            )
            assert value == '100', (
                f"Expected value '100', got '{value}'"
            )
            break

    print("✓ chromium_tuple returns correct ForegroundBrightnessThreshold key")
